import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterModule } from '@angular/router';
import { PromptService, Prompt } from '../prompt.service';

@Component({
  selector: 'app-prompt-detail',
  standalone: false,
  template: `
    <div *ngIf="loading" class="loading">Loading...</div>
    <div *ngIf="!loading && prompt" class="card">
      <h2>{{ prompt.title }}</h2>
      <span class="badge" [ngClass]="getComplexityClass(prompt.complexity)">
        Complexity: {{ prompt.complexity }}/10
      </span>
      <p class="view-count">Views: {{ prompt.view_count }}</p>
      <div class="prompt-content">
        {{ prompt.content }}
      </div>
      <div class="actions">
        <a routerLink="/prompts" class="btn btn-secondary">Back to List</a>
      </div>
    </div>
    <div *ngIf="!loading && !prompt" class="empty-state">
      <p>Prompt not found.</p>
      <a routerLink="/prompts" class="btn">Back to List</a>
    </div>
  `,
  styles: [`:host { display: block; }`]
})
export class PromptDetailComponent implements OnInit {
  prompt: Prompt | null = null;
  loading = true;

  constructor(
    private route: ActivatedRoute,
    private promptService: PromptService
  ) { }

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.promptService.getPrompt(id).subscribe({
        next: (res) => {
          this.prompt = res;
          this.loading = false;
        },
        error: () => {
          this.loading = false;
        }
      });
    }
  }

  getComplexityClass(level: number): string {
    if (level <= 3) return 'badge-low';
    if (level <= 7) return 'badge-medium';
    return 'badge-high';
  }
}
